import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import axios from 'axios';
import Login from './components/Auth/Login';
import SignUp from './components/Auth/SignUp';
import Landing from './components/Landing';
import Dashboard from './components/Dashboard/Dashboard';
import Customers from './components/Customers/Customers';
import Vendors from './components/Vendors/Vendors';
import Items from './components/Items/Items';
import Invoices from './components/Invoices/Invoices';
import PurchaseOrdersDashboard from './components/PurchaseOrders/PurchaseOrdersDashboard';
import PurchaseOrderForm from './components/PurchaseOrders/PurchaseOrderForm';
import ProtectedRoute from './components/Common/ProtectedRoute';
import RecurringPage from './components/Recurring/RecurringPage';
import './App.css';

// Configure axios defaults - UPDATE PORT TO 5002
axios.defaults.withCredentials = true;
axios.defaults.baseURL = 'http://localhost:5002/api';

// Add request interceptor for error handling
axios.interceptors.response.use(
  (response) => response,
  (error) => {
    if (error.response?.status === 401) {
      localStorage.removeItem('token');
      window.location.href = '/login';
    }
    return Promise.reject(error);
  }
);

function App() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [loading, setLoading] = useState(true);
  const [user, setUser] = useState(null);
  const [serverError, setServerError] = useState(false);

  useEffect(() => {
    const checkAuth = async () => {
      try {
        setServerError(false);
        const response = await axios.get('/auth/check');
        if (response.data.authenticated) {
          setIsAuthenticated(true);
          setUser(response.data.user);
        } else {
          setIsAuthenticated(false);
        }
      } catch (error) {
        console.error('Auth check failed:', error);
        setIsAuthenticated(false);
        
        if (error.code === 'ERR_NETWORK') {
          setServerError(true);
          console.error('Cannot connect to server. Make sure backend is running on port 5002');
        }
      } finally {
        setLoading(false);
      }
    };
    checkAuth();
  }, []);

  const handleLogin = (userData) => {
    setIsAuthenticated(true);
    setUser(userData);
    setServerError(false);
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setUser(null);
  };

  if (loading) {
    return (
      <div className="loading-container">
        <div className="loading-spinner"></div>
        <p>Loading...</p>
      </div>
    );
  }

  if (serverError) {
    return (
      <div className="loading-container">
        <div className="error-message" style={{ textAlign: 'center', maxWidth: '500px', margin: '0 auto' }}>
          <h2>⚠️ Server Connection Error</h2>
          <p>Cannot connect to the backend server.</p>
          <p style={{ fontSize: '14px', marginTop: '10px' }}>
            Make sure backend is running on port 5002:<br/>
            <code>cd backend && npm run dev</code>
          </p>
          <button 
            onClick={() => window.location.reload()} 
            className="btn-primary" 
            style={{ marginTop: '20px' }}
          >
            Retry Connection
          </button>
        </div>
      </div>
    );
  }

  return (
    <Router>
      <Routes>
        <Route path="/login" element={<Login onLogin={handleLogin} />} />
        <Route path="/signup" element={<SignUp />} />
        <Route path="/" element={isAuthenticated ? <Navigate to="/dashboard" /> : <Landing />} />
        <Route path="/dashboard" element={
          <ProtectedRoute isAuthenticated={isAuthenticated}>
            <Dashboard onLogout={handleLogout} user={user} />
          </ProtectedRoute>
        } />
        <Route path="/customers" element={
          <ProtectedRoute isAuthenticated={isAuthenticated}>
            <Customers onLogout={handleLogout} user={user} />
          </ProtectedRoute>
        } />
        <Route path="/vendors" element={
          <ProtectedRoute isAuthenticated={isAuthenticated}>
            <Vendors onLogout={handleLogout} user={user} />
          </ProtectedRoute>
        } />
        <Route path="/items" element={
          <ProtectedRoute isAuthenticated={isAuthenticated}>
            <Items onLogout={handleLogout} user={user} />
          </ProtectedRoute>
        } />
        <Route path="/invoices" element={
          <ProtectedRoute isAuthenticated={isAuthenticated}>
            <Invoices onLogout={handleLogout} user={user} />
          </ProtectedRoute>
        } />
        <Route path="/recurring" element={
          <ProtectedRoute isAuthenticated={isAuthenticated}>
            <RecurringPage onLogout={handleLogout} user={user} />
          </ProtectedRoute>
        } />
        <Route path="/purchase-orders" element={
          <ProtectedRoute isAuthenticated={isAuthenticated}>
            <PurchaseOrdersDashboard onLogout={handleLogout} user={user} />
          </ProtectedRoute>
        } />
        <Route path="/purchase-orders/new" element={
          <ProtectedRoute isAuthenticated={isAuthenticated}>
            <PurchaseOrderForm onLogout={handleLogout} user={user} />
          </ProtectedRoute>
        } />
      </Routes>
    </Router>
  );
}

export default App;
